    parts = line.split()
    if len(parts) >= 3 and parts[1].lower() in ('t','T'):
        symbols.append((int(parts[0], 16), parts[2]))

targets = [0x2f4b20, 0x2f4c84]
for t in targets:
    best = None
    for addr, name in symbols:
        if addr <= t:
            best = (addr, name)
        else:
            break
    if best:
        print(f'0x{t:x} -> {best[1]}+0x{t-best[0]:x} (base 0x{best[0]:x})')
    else:
        print(f'0x{t:x} -> ??')
"

