result = subprocess.run(['aarch64-linux-gnu-readelf', '-rW', 'libmonosgen-2.0.so'], capture_output=True, text=True)
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 1:
        try:
            addr = int(parts[0], 16)
            if 0x2f4b00 <= addr <= 0x2f4ca0:
                print(line)
        except:
            pass
